156	// Definimos uma estrutura que armazenará dados necessários para renderizar
157	// cada objeto da cena virtual.
158	struct SceneObject
159	{
160	    std::string  name;        // Nome do objeto
161	    size_t       first_index; // Índice do primeiro vértice dentro do vetor indices[] definido em BuildTrianglesAndAddToVirtualScene()
162	    size_t       num_indices; // Número de índices do objeto dentro do vetor indices[] definido em BuildTrianglesAndAddToVirtualScene()
163	    GLenum       rendering_mode; // Modo de rasterização (GL_TRIANGLES, GL_TRIANGLE_STRIP, etc.)
164	    GLuint       vertex_array_object_id; // ID do VAO onde estão armazenados os atributos do modelo
165	    glm::vec3    bbox_min; // Axis-Aligned Bounding Box do objeto
