194	// Variáveis que definem a câmera em coordenadas esféricas, controladas pelo
195	// usuário através do mouse (veja função CursorPosCallback()). A posição
196	// efetiva da câmera é calculada dentro da função main(), dentro do loop de
197	// renderização.
198	float g_CameraTheta = 0.0f; // Ângulo no plano ZX em relação ao eixo Z
199	float g_CameraPhi = 0.0f;   // Ângulo em relação ao eixo Y
200	float g_CameraDistance = 3.5f; // Distância da câmera para a origem
201	
202	// Variáveis que controlam rotação do antebraço
203	float g_ForearmAngleZ = 0.0f;
204	float g_ForearmAngleX = 0.0f;
