484	// Função que carrega uma imagem para ser utilizada como textura
485	void LoadTextureImage(const char* filename)
486	{
487	    printf("Carregando imagem \"%s\"... ", filename);
488	
489	    // Primeiro fazemos a leitura da imagem do disco
490	    stbi_set_flip_vertically_on_load(true);
491	    int width;
492	    int height;
493	    int channels;
494	    unsigned char *data = stbi_load(filename, &width, &height, &channels, 3);
495	
496	    if ( data == NULL )
497	    {
498	        fprintf(stderr, "ERROR: Cannot open image file \"%s\".\n", filename);
499	        std::exit(EXIT_FAILURE);
500	    }
501	
502	    printf("OK (%dx%d).\n", width, height);
503	
504	    // Agora criamos objetos na GPU com OpenGL para armazenar a textura
505	    GLuint texture_id;
506	    GLuint sampler_id;
507	    glGenTextures(1, &texture_id);
508	    glGenSamplers(1, &sampler_id);
509	
510	    // Veja slides 95-96 do documento Aula_20_Mapeamento_de_Texturas.pdf
511	    glSamplerParameteri(sampler_id, GL_TEXTURE_WRAP_S, GL_CLAMP_TO_EDGE);
512	    glSamplerParameteri(sampler_id, GL_TEXTURE_WRAP_T, GL_CLAMP_TO_EDGE);
513	
514	    // Parâmetros de amostragem da textura.
515	    glSamplerParameteri(sampler_id, GL_TEXTURE_MIN_FILTER, GL_LINEAR_MIPMAP_LINEAR);
516	    glSamplerParameteri(sampler_id, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
517	
518	    // Agora enviamos a imagem lida do disco para a GPU
519	    glPixelStorei(GL_UNPACK_ALIGNMENT, 1);
520	    glPixelStorei(GL_UNPACK_ROW_LENGTH, 0);
521	    glPixelStorei(GL_UNPACK_SKIP_PIXELS, 0);
522	    glPixelStorei(GL_UNPACK_SKIP_ROWS, 0);
523	
524	    GLuint textureunit = g_NumLoadedTextures;
525	    glActiveTexture(GL_TEXTURE0 + textureunit);
526	    glBindTexture(GL_TEXTURE_2D, texture_id);
527	    glTexImage2D(GL_TEXTURE_2D, 0, GL_SRGB8, width, height, 0, GL_RGB, GL_UNSIGNED_BYTE, data);
528	    glGenerateMipmap(GL_TEXTURE_2D);
529	    glBindSampler(textureunit, sampler_id);
530	
531	    stbi_image_free(data);
532	
533	    g_NumLoadedTextures += 1;
534	}
