536	// Função que desenha um objeto armazenado em g_VirtualScene. Veja definição
537	// dos objetos na função BuildTrianglesAndAddToVirtualScene().
538	void DrawVirtualObject(const char* object_name)
539	{
540	    // "Ligamos" o VAO. Informamos que queremos utilizar os atributos de
541	    // vértices apontados pelo VAO criado pela função BuildTrianglesAndAddToVirtualScene(). Veja
542	    // comentários detalhados dentro da definição de BuildTrianglesAndAddToVirtualScene().
543	    glBindVertexArray(g_VirtualScene[object_name].vertex_array_object_id);
544	
545	    // Setamos as variáveis "bbox_min" e "bbox_max" do fragment shader
546	    // com os parâmetros da axis-aligned bounding box (AABB) do modelo.
547	    glm::vec3 bbox_min = g_VirtualScene[object_name].bbox_min;
548	    glm::vec3 bbox_max = g_VirtualScene[object_name].bbox_max;
549	    glUniform4f(g_bbox_min_uniform, bbox_min.x, bbox_min.y, bbox_min.z, 1.0f);
550	    glUniform4f(g_bbox_max_uniform, bbox_max.x, bbox_max.y, bbox_max.z, 1.0f);
551	
552	    // Pedimos para a GPU rasterizar os vértices dos eixos XYZ
553	    // apontados pelo VAO como linhas. Veja a definição de
554	    // g_VirtualScene[""] dentro da função BuildTrianglesAndAddToVirtualScene(), e veja
555	    // a documentação da função glDrawElements() em
556	    // http://docs.gl/gl3/glDrawElements.
557	    glDrawElements(
558	        g_VirtualScene[object_name].rendering_mode,
559	        g_VirtualScene[object_name].num_indices,
560	        GL_UNSIGNED_INT,
561	        (void*)(g_VirtualScene[object_name].first_index * sizeof(GLuint))
562	    );
563	
564	    // "Desligamos" o VAO, evitando assim que operações posteriores venham a
565	    // alterar o mesmo. Isso evita bugs.
566	    glBindVertexArray(0);
567	}
