569	// Função que carrega os shaders de vértices e de fragmentos que serão
570	// utilizados para renderização. Veja slides 180-200 do documento Aula_03_Rendering_Pipeline_Grafico.pdf.
571	//
572	void LoadShadersFromFiles()
573	{
574	    // Note que o caminho para os arquivos "shader_vertex.glsl" e
575	    // "shader_fragment.glsl" estão fixados, sendo que assumimos a existência
576	    // da seguinte estrutura no sistema de arquivos:
577	    //
578	    //    + FCG_Lab_01/
579	    //    |
580	    //    +--+ bin/
581	    //    |  |
582	    //    |  +--+ Release/  (ou Debug/ ou Linux/)
583	    //    |     |
584	    //    |     o-- main.exe
585	    //    |
586	    //    +--+ src/
587	    //       |
588	    //       o-- shader_vertex.glsl
589	    //       |
590	    //       o-- shader_fragment.glsl
591	    //
592	    GLuint vertex_shader_id = LoadShader_Vertex("../../src/shader_vertex.glsl");
593	    GLuint fragment_shader_id = LoadShader_Fragment("../../src/shader_fragment.glsl");
594	
595	    // Deletamos o programa de GPU anterior, caso ele exista.
596	    if ( g_GpuProgramID != 0 )
597	        glDeleteProgram(g_GpuProgramID);
598	
599	    // Criamos um programa de GPU utilizando os shaders carregados acima.
600	    g_GpuProgramID = CreateGpuProgram(vertex_shader_id, fragment_shader_id);
601	
602	    // Buscamos o endereço das variáveis definidas dentro do Vertex Shader.
603	    // Utilizaremos estas variáveis para enviar dados para a placa de vídeo
604	    // (GPU)! Veja arquivo "shader_vertex.glsl" e "shader_fragment.glsl".
605	    g_model_uniform      = glGetUniformLocation(g_GpuProgramID, "model"); // Variável da matriz "model"
606	    g_view_uniform       = glGetUniformLocation(g_GpuProgramID, "view"); // Variável da matriz "view" em shader_vertex.glsl
607	    g_projection_uniform = glGetUniformLocation(g_GpuProgramID, "projection"); // Variável da matriz "projection" em shader_vertex.glsl
608	    g_object_id_uniform  = glGetUniformLocation(g_GpuProgramID, "object_id"); // Variável "object_id" em shader_fragment.glsl
609	    g_bbox_min_uniform   = glGetUniformLocation(g_GpuProgramID, "bbox_min");
610	    g_bbox_max_uniform   = glGetUniformLocation(g_GpuProgramID, "bbox_max");
611	
612	    // Variáveis em "shader_fragment.glsl" para acesso das imagens de textura
613	    glUseProgram(g_GpuProgramID);
614	    glUniform1i(glGetUniformLocation(g_GpuProgramID, "TextureImage0"), 0);
615	    glUniform1i(glGetUniformLocation(g_GpuProgramID, "TextureImage1"), 1);
616	    glUniform1i(glGetUniformLocation(g_GpuProgramID, "TextureImage2"), 2);
617	    glUseProgram(0);
618	}
