758	// Constrói triângulos para futura renderização a partir de um ObjModel.
759	void BuildTrianglesAndAddToVirtualScene(ObjModel* model)
760	{
761	    GLuint vertex_array_object_id;
762	    glGenVertexArrays(1, &vertex_array_object_id);
763	    glBindVertexArray(vertex_array_object_id);
764	
765	    std::vector<GLuint> indices;
766	    std::vector<float>  model_coefficients;
767	    std::vector<float>  normal_coefficients;
768	    std::vector<float>  texture_coefficients;
769	
770	    for (size_t shape = 0; shape < model->shapes.size(); ++shape)
771	    {
772	        size_t first_index = indices.size();
773	        size_t num_triangles = model->shapes[shape].mesh.num_face_vertices.size();
774	
775	        const float minval = std::numeric_limits<float>::min();
776	        const float maxval = std::numeric_limits<float>::max();
777	
778	        glm::vec3 bbox_min = glm::vec3(maxval,maxval,maxval);
779	        glm::vec3 bbox_max = glm::vec3(minval,minval,minval);
780	
781	        for (size_t triangle = 0; triangle < num_triangles; ++triangle)
782	        {
783	            assert(model->shapes[shape].mesh.num_face_vertices[triangle] == 3);
784	
785	            for (size_t vertex = 0; vertex < 3; ++vertex)
786	            {
787	                tinyobj::index_t idx = model->shapes[shape].mesh.indices[3*triangle + vertex];
788	
789	                indices.push_back(first_index + 3*triangle + vertex);
790	
791	                const float vx = model->attrib.vertices[3*idx.vertex_index + 0];
792	                const float vy = model->attrib.vertices[3*idx.vertex_index + 1];
793	                const float vz = model->attrib.vertices[3*idx.vertex_index + 2];
794	                //printf("tri %d vert %d = (%.2f, %.2f, %.2f)\n", (int)triangle, (int)vertex, vx, vy, vz);
795	                model_coefficients.push_back( vx ); // X
796	                model_coefficients.push_back( vy ); // Y
797	                model_coefficients.push_back( vz ); // Z
798	                model_coefficients.push_back( 1.0f ); // W
799	
800	                bbox_min.x = std::min(bbox_min.x, vx);
801	                bbox_min.y = std::min(bbox_min.y, vy);
802	                bbox_min.z = std::min(bbox_min.z, vz);
803	                bbox_max.x = std::max(bbox_max.x, vx);
804	                bbox_max.y = std::max(bbox_max.y, vy);
805	                bbox_max.z = std::max(bbox_max.z, vz);
806	
807	                // Inspecionando o código da tinyobjloader, o aluno Bernardo
808	                // Sulzbach (2017/1) apontou que a maneira correta de testar se
809	                // existem normais e coordenadas de textura no ObjModel é
810	                // comparando se o índice retornado é -1. Fazemos isso abaixo.
811	
812	                if ( idx.normal_index != -1 )
813	                {
814	                    const float nx = model->attrib.normals[3*idx.normal_index + 0];
815	                    const float ny = model->attrib.normals[3*idx.normal_index + 1];
816	                    const float nz = model->attrib.normals[3*idx.normal_index + 2];
817	                    normal_coefficients.push_back( nx ); // X
818	                    normal_coefficients.push_back( ny ); // Y
819	                    normal_coefficients.push_back( nz ); // Z
820	                    normal_coefficients.push_back( 0.0f ); // W
821	                }
822	
823	                if ( idx.texcoord_index != -1 )
824	                {
825	                    const float u = model->attrib.texcoords[2*idx.texcoord_index + 0];
826	                    const float v = model->attrib.texcoords[2*idx.texcoord_index + 1];
827	                    texture_coefficients.push_back( u );
828	                    texture_coefficients.push_back( v );
829	                }
830	            }
831	        }
832	
833	        size_t last_index = indices.size() - 1;
834	
835	        SceneObject theobject;
836	        theobject.name           = model->shapes[shape].name;
837	        theobject.first_index    = first_index; // Primeiro índice
838	        theobject.num_indices    = last_index - first_index + 1; // Número de indices
839	        theobject.rendering_mode = GL_TRIANGLES;       // Índices correspondem ao tipo de rasterização GL_TRIANGLES.
840	        theobject.vertex_array_object_id = vertex_array_object_id;
841	
842	        theobject.bbox_min = bbox_min;
843	        theobject.bbox_max = bbox_max;
844	
845	        g_VirtualScene[model->shapes[shape].name] = theobject;
846	    }
847	
848	    GLuint VBO_model_coefficients_id;
849	    glGenBuffers(1, &VBO_model_coefficients_id);
850	    glBindBuffer(GL_ARRAY_BUFFER, VBO_model_coefficients_id);
851	    glBufferData(GL_ARRAY_BUFFER, model_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
852	    glBufferSubData(GL_ARRAY_BUFFER, 0, model_coefficients.size() * sizeof(float), model_coefficients.data());
853	    GLuint location = 0; // "(location = 0)" em "shader_vertex.glsl"
854	    GLint  number_of_dimensions = 4; // vec4 em "shader_vertex.glsl"
855	    glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
856	    glEnableVertexAttribArray(location);
857	    glBindBuffer(GL_ARRAY_BUFFER, 0);
858	
859	    if ( !normal_coefficients.empty() )
860	    {
861	        GLuint VBO_normal_coefficients_id;
862	        glGenBuffers(1, &VBO_normal_coefficients_id);
863	        glBindBuffer(GL_ARRAY_BUFFER, VBO_normal_coefficients_id);
864	        glBufferData(GL_ARRAY_BUFFER, normal_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
865	        glBufferSubData(GL_ARRAY_BUFFER, 0, normal_coefficients.size() * sizeof(float), normal_coefficients.data());
866	        location = 1; // "(location = 1)" em "shader_vertex.glsl"
867	        number_of_dimensions = 4; // vec4 em "shader_vertex.glsl"
868	        glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
869	        glEnableVertexAttribArray(location);
870	        glBindBuffer(GL_ARRAY_BUFFER, 0);
871	    }
872	
873	    if ( !texture_coefficients.empty() )
874	    {
875	        GLuint VBO_texture_coefficients_id;
876	        glGenBuffers(1, &VBO_texture_coefficients_id);
877	        glBindBuffer(GL_ARRAY_BUFFER, VBO_texture_coefficients_id);
878	        glBufferData(GL_ARRAY_BUFFER, texture_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
879	        glBufferSubData(GL_ARRAY_BUFFER, 0, texture_coefficients.size() * sizeof(float), texture_coefficients.data());
880	        location = 2; // "(location = 1)" em "shader_vertex.glsl"
881	        number_of_dimensions = 2; // vec2 em "shader_vertex.glsl"
882	        glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
883	        glEnableVertexAttribArray(location);
884	        glBindBuffer(GL_ARRAY_BUFFER, 0);
885	    }
886	
887	    GLuint indices_id;
888	    glGenBuffers(1, &indices_id);
889	
890	    // "Ligamos" o buffer. Note que o tipo agora é GL_ELEMENT_ARRAY_BUFFER.
891	    glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, indices_id);
892	    glBufferData(GL_ELEMENT_ARRAY_BUFFER, indices.size() * sizeof(GLuint), NULL, GL_STATIC_DRAW);
893	    glBufferSubData(GL_ELEMENT_ARRAY_BUFFER, 0, indices.size() * sizeof(GLuint), indices.data());
894	    // glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, 0); // XXX Errado!
895	    //
896	
897	    // "Desligamos" o VAO, evitando assim que operações posteriores venham a
898	    // alterar o mesmo. Isso evita bugs.
899	    glBindVertexArray(0);
900	}
