902	// Carrega um Vertex Shader de um arquivo GLSL. Veja definição de LoadShader() abaixo.
903	GLuint LoadShader_Vertex(const char* filename)
904	{
905	    // Criamos um identificador (ID) para este shader, informando que o mesmo
906	    // será aplicado nos vértices.
907	    GLuint vertex_shader_id = glCreateShader(GL_VERTEX_SHADER);
908	
909	    // Carregamos e compilamos o shader
910	    LoadShader(filename, vertex_shader_id);
911	
912	    // Retorna o ID gerado acima
913	    return vertex_shader_id;
914	}
