916	// Carrega um Fragment Shader de um arquivo GLSL . Veja definição de LoadShader() abaixo.
917	GLuint LoadShader_Fragment(const char* filename)
918	{
919	    // Criamos um identificador (ID) para este shader, informando que o mesmo
920	    // será aplicado nos fragmentos.
921	    GLuint fragment_shader_id = glCreateShader(GL_FRAGMENT_SHADER);
922	
923	    // Carregamos e compilamos o shader
924	    LoadShader(filename, fragment_shader_id);
925	
926	    // Retorna o ID gerado acima
927	    return fragment_shader_id;
