930	// Função auxilar, utilizada pelas duas funções acima. Carrega código de GPU de
931	// um arquivo GLSL e faz sua compilação.
932	void LoadShader(const char* filename, GLuint shader_id)
933	{
934	    // Lemos o arquivo de texto indicado pela variável "filename"
935	    // e colocamos seu conteúdo em memória, apontado pela variável
936	    // "shader_string".
937	    std::ifstream file;
938	    try {
939	        file.exceptions(std::ifstream::failbit);
940	        file.open(filename);
941	    } catch ( std::exception& e ) {
942	        fprintf(stderr, "ERROR: Cannot open file \"%s\".\n", filename);
943	        std::exit(EXIT_FAILURE);
944	    }
945	    std::stringstream shader;
946	    shader << file.rdbuf();
947	    std::string str = shader.str();
948	    const GLchar* shader_string = str.c_str();
949	    const GLint   shader_string_length = static_cast<GLint>( str.length() );
950	
951	    // Define o código do shader GLSL, contido na string "shader_string"
952	    glShaderSource(shader_id, 1, &shader_string, &shader_string_length);
953	
954	    // Compila o código do shader GLSL (em tempo de execução)
955	    glCompileShader(shader_id);
956	
957	    // Verificamos se ocorreu algum erro ou "warning" durante a compilação
958	    GLint compiled_ok;
959	    glGetShaderiv(shader_id, GL_COMPILE_STATUS, &compiled_ok);
960	
961	    GLint log_length = 0;
962	    glGetShaderiv(shader_id, GL_INFO_LOG_LENGTH, &log_length);
963	
964	    // Alocamos memória para guardar o log de compilação.
965	    // A chamada "new" em C++ é equivalente ao "malloc()" do C.
966	    GLchar* log = new GLchar[log_length];
967	    glGetShaderInfoLog(shader_id, log_length, &log_length, log);
968	
969	    // Imprime no terminal qualquer erro ou "warning" de compilação
970	    if ( log_length != 0 )
971	    {
972	        std::string  output;
973	
974	        if ( !compiled_ok )
975	        {
976	            output += "ERROR: OpenGL compilation of \"";
977	            output += filename;
978	            output += "\" failed.\n";
979	            output += "== Start of compilation log\n";
980	            output += log;
981	            output += "== End of compilation log\n";
982	        }
983	        else
984	        {
985	            output += "WARNING: OpenGL compilation of \"";
986	            output += filename;
987	            output += "\".\n";
988	            output += "== Start of compilation log\n";
989	            output += log;
990	            output += "== End of compilation log\n";
991	        }
992	
993	        fprintf(stderr, "%s", output.c_str());
994	    }
995	
996	    // A chamada "delete" em C++ é equivalente ao "free()" do C
997	    delete [] log;
998	}
