1000	// Esta função cria um programa de GPU, o qual contém obrigatoriamente um
1001	// Vertex Shader e um Fragment Shader.
1002	GLuint CreateGpuProgram(GLuint vertex_shader_id, GLuint fragment_shader_id)
1003	{
1004	    // Criamos um identificador (ID) para este programa de GPU
1005	    GLuint program_id = glCreateProgram();
1006	
1007	    // Definição dos dois shaders GLSL que devem ser executados pelo programa
1008	    glAttachShader(program_id, vertex_shader_id);
1009	    glAttachShader(program_id, fragment_shader_id);
1010	
1011	    // Linkagem dos shaders acima ao programa
1012	    glLinkProgram(program_id);
1013	
1014	    // Verificamos se ocorreu algum erro durante a linkagem
1015	    GLint linked_ok = GL_FALSE;
1016	    glGetProgramiv(program_id, GL_LINK_STATUS, &linked_ok);
1017	
1018	    // Imprime no terminal qualquer erro de linkagem
1019	    if ( linked_ok == GL_FALSE )
1020	    {
1021	        GLint log_length = 0;
1022	        glGetProgramiv(program_id, GL_INFO_LOG_LENGTH, &log_length);
1023	
1024	        // Alocamos memória para guardar o log de compilação.
1025	        // A chamada "new" em C++ é equivalente ao "malloc()" do C.
1026	        GLchar* log = new GLchar[log_length];
1027	
1028	        glGetProgramInfoLog(program_id, log_length, &log_length, log);
1029	
1030	        std::string output;
1031	
1032	        output += "ERROR: OpenGL linking of program failed.\n";
1033	        output += "== Start of link log\n";
1034	        output += log;
1035	        output += "\n== End of link log\n";
1036	
1037	        // A chamada "delete" em C++ é equivalente ao "free()" do C
1038	        delete [] log;
1039	
1040	        fprintf(stderr, "%s", output.c_str());
1041	    }
1042	
1043	    // Os "Shader Objects" podem ser marcados para deleção após serem linkados 
1044	    glDeleteShader(vertex_shader_id);
1045	    glDeleteShader(fragment_shader_id);
1046	
1047	    // Retornamos o ID gerado acima
1048	    return program_id;
1049	}
