1057	    // função "glViewport" define o mapeamento das "normalized device
1058	    // coordinates" (NDC) para "pixel coordinates".  Essa é a operação de
1059	    // "Screen Mapping" ou "Viewport Mapping" vista em aula ({+ViewportMapping2+}).
1060	    glViewport(0, 0, width, height);
