1095	    }
1096	    if (button == GLFW_MOUSE_BUTTON_RIGHT && action == GLFW_PRESS)
1097	    {
1098	        // Se o usuário pressionou o botão esquerdo do mouse, guardamos a
1099	        // posição atual do cursor nas variáveis g_LastCursorPosX e
1100	        // g_LastCursorPosY.  Também, setamos a variável
1101	        // g_RightMouseButtonPressed como true, para saber que o usuário está
1102	        // com o botão esquerdo pressionado.
1103	        glfwGetCursorPos(window, &g_LastCursorPosX, &g_LastCursorPosY);
1104	        g_RightMouseButtonPressed = true;
1105	    }
1106	    if (button == GLFW_MOUSE_BUTTON_RIGHT && action == GLFW_RELEASE)
1107	    {
1108	        // Quando o usuário soltar o botão esquerdo do mouse, atualizamos a
