1130	// Função callback chamada sempre que o usuário movimentar o cursor do mouse em
1131	// cima da janela OpenGL.
1132	void CursorPosCallback(GLFWwindow* window, double xpos, double ypos)
1133	{
1134	    // Abaixo executamos o seguinte: caso o botão esquerdo do mouse esteja
1135	    // pressionado, computamos quanto que o mouse se movimento desde o último
1136	    // instante de tempo, e usamos esta movimentação para atualizar os
1137	    // parâmetros que definem a posição da câmera dentro da cena virtual.
1138	    // Assim, temos que o usuário consegue controlar a câmera.
1139	
1140	    if (g_LeftMouseButtonPressed)
1141	    {
1142	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1143	        float dx = xpos - g_LastCursorPosX;
1144	        float dy = ypos - g_LastCursorPosY;
1145	    
1146	        // Atualizamos parâmetros da câmera com os deslocamentos
1147	        g_CameraTheta -= 0.01f*dx;
1148	        g_CameraPhi   += 0.01f*dy;
1149	    
1150	        // Em coordenadas esféricas, o ângulo phi deve ficar entre -pi/2 e +pi/2.
1151	        float phimax = 3.141592f/2;
1152	        float phimin = -phimax;
1153	    
1154	        if (g_CameraPhi > phimax)
1155	            g_CameraPhi = phimax;
1156	    
1157	        if (g_CameraPhi < phimin)
1158	            g_CameraPhi = phimin;
1159	    
1160	        // Atualizamos as variáveis globais para armazenar a posição atual do
1161	        // cursor como sendo a última posição conhecida do cursor.
1162	        g_LastCursorPosX = xpos;
1163	        g_LastCursorPosY = ypos;
1164	    }
1165	
1166	    if (g_RightMouseButtonPressed)
1167	    {
1168	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1169	        float dx = xpos - g_LastCursorPosX;
1170	        float dy = ypos - g_LastCursorPosY;
1171	    
1172	        // Atualizamos parâmetros da antebraço com os deslocamentos
1173	        g_ForearmAngleZ -= 0.01f*dx;
1174	        g_ForearmAngleX += 0.01f*dy;
1175	    
1176	        // Atualizamos as variáveis globais para armazenar a posição atual do
1177	        // cursor como sendo a última posição conhecida do cursor.
1178	        g_LastCursorPosX = xpos;
1179	        g_LastCursorPosY = ypos;
1180	    }
1181	
1182	    if (g_MiddleMouseButtonPressed)
1183	    {
1184	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1185	        float dx = xpos - g_LastCursorPosX;
1186	        float dy = ypos - g_LastCursorPosY;
1187	    
1188	        // Atualizamos parâmetros da antebraço com os deslocamentos
1189	        g_TorsoPositionX += 0.01f*dx;
1190	        g_TorsoPositionY -= 0.01f*dy;
1191	    
1192	        // Atualizamos as variáveis globais para armazenar a posição atual do
1193	        // cursor como sendo a última posição conhecida do cursor.
1194	        g_LastCursorPosX = xpos;
1195	        g_LastCursorPosY = ypos;
1196	    }
1197	}
