1199	// Função callback chamada sempre que o usuário movimenta a "rodinha" do mouse.
1200	void ScrollCallback(GLFWwindow* window, double xoffset, double yoffset)
1201	{
1202	    // Atualizamos a distância da câmera para a origem utilizando a
1203	    // movimentação da "rodinha", simulando um ZOOM.
1204	    g_CameraDistance -= 0.1f*yoffset;
1205	
1206	    // Uma câmera look-at nunca pode estar exatamente "em cima" do ponto para
1207	    // onde ela está olhando, pois isto gera problemas de divisão por zero na
1208	    // definição do sistema de coordenadas da câmera. Isto é, a variável abaixo
1209	    // nunca pode ser zero. Versões anteriores deste código possuíam este bug,
1210	    // o qual foi detectado pelo aluno Vinicius Fraga (2017/2).
1211	    const float verysmallnumber = std::numeric_limits<float>::epsilon();
1212	    if (g_CameraDistance < verysmallnumber)
1213	        g_CameraDistance = verysmallnumber;
1214	}
