1217	
1218	// Definição da função que será chamada sempre que o usuário pressionar alguma
1219	// tecla do teclado. Veja http://www.glfw.org/docs/latest/input_guide.html#input_key
1220	void KeyCallback(GLFWwindow* window, int key, int scancode, int action, int mod)
1221	{
1222	    // =======================
1223	    // Não modifique esta chamada! Ela é utilizada para correção automatizada dos
1224	    // laboratórios. Deve ser sempre o primeiro comando desta função KeyCallback().
1225	    Correcao_KeyCallback(key, action, mod);
1226	    // =======================
1227	
1228	    // Se o usuário pressionar a tecla ESC, fechamos a janela.
1229	    if (key == GLFW_KEY_ESCAPE && action == GLFW_PRESS)
1230	        glfwSetWindowShouldClose(window, GL_TRUE);
1231	
1232	    // O código abaixo implementa a seguinte lógica:
1233	    //   Se apertar tecla X       então g_AngleX += delta;
1234	    //   Se apertar tecla shift+X então g_AngleX -= delta;
1235	    //   Se apertar tecla Y       então g_AngleY += delta;
1236	    //   Se apertar tecla shift+Y então g_AngleY -= delta;
1237	    //   Se apertar tecla Z       então g_AngleZ += delta;
1238	    //   Se apertar tecla shift+Z então g_AngleZ -= delta;
1239	
1240	    float delta = 3.141592 / 16; // 22.5 graus, em radianos.
1241	
1242	    if (key == GLFW_KEY_X && action == GLFW_PRESS)
1243	    {
1244	        g_AngleX += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1245	    }
1246	
1247	    if (key == GLFW_KEY_Y && action == GLFW_PRESS)
1248	    {
1249	        g_AngleY += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1250	    }
1251	    if (key == GLFW_KEY_Z && action == GLFW_PRESS)
1252	    {
1253	        g_AngleZ += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1254	    }
1255	
1256	    // Se o usuário apertar a tecla espaço, resetamos os ângulos de Euler para zero.
1257	    if (key == GLFW_KEY_SPACE && action == GLFW_PRESS)
1258	    {
1259	        g_AngleX = 0.0f;
1260	        g_AngleY = 0.0f;
1261	        g_AngleZ = 0.0f;
1262	        g_ForearmAngleX = 0.0f;
1263	        g_ForearmAngleZ = 0.0f;
1264	        g_TorsoPositionX = 0.0f;
1265	        g_TorsoPositionY = 0.0f;
1266	    }
1267	
1268	    // Se o usuário apertar a tecla P, utilizamos projeção perspectiva.
1269	    if (key == GLFW_KEY_P && action == GLFW_PRESS)
1270	    {
1271	        g_UsePerspectiveProjection = true;
1272	    }
1273	
1274	    // Se o usuário apertar a tecla O, utilizamos projeção ortográfica.
1275	    if (key == GLFW_KEY_O && action == GLFW_PRESS)
1276	    {
1277	        g_UsePerspectiveProjection = false;
1278	    }
1279	
1280	    // Se o usuário apertar a tecla H, fazemos um "toggle" do texto informativo mostrado na tela.
1281	    if (key == GLFW_KEY_H && action == GLFW_PRESS)
1282	    {
1283	        g_ShowInfoText = !g_ShowInfoText;
1284	    }
1285	
1286	    // Se o usuário apertar a tecla R, recarregamos os shaders dos arquivos "shader_fragment.glsl" e "shader_vertex.glsl".
1287	    if (key == GLFW_KEY_R && action == GLFW_PRESS)
1288	    {
1289	        LoadShadersFromFiles();
1290	        fprintf(stdout,"Shaders recarregados!\n");
1291	        fflush(stdout);
1292	    }
1293	}
